// frontend/src/pages/AdminPage.js
import { useState, useEffect } from 'react';
import API from '../api/axios';

const AdminPage = () => {
  const [users, setUsers]   = useState([]);
  const [posts, setPosts]   = useState([]);
  const [tab, setTab]       = useState('users');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      API.get('/admin/users'),
      API.get('/admin/posts'),
    ])
      .then(([usersRes, postsRes]) => {
        setUsers(usersRes.data);
        setPosts(postsRes.data);
      })
      .finally(() => setLoading(false));
  }, []);

  const toggleStatus = async (id) => {
    try {
      const { data } = await API.put(`/admin/users/${id}/status`);
      setUsers(users.map(u => u._id === id ? data.user : u));
    } catch {
      alert('Failed to update user status.');
    }
  };

  const removePost = async (id) => {
    if (!window.confirm('Mark this post as removed?')) return;
    try {
      await API.put(`/admin/posts/${id}/remove`);
      setPosts(posts.map(p => p._id === id ? { ...p, status: 'removed' } : p));
    } catch {
      alert('Failed to remove post.');
    }
  };

  const tabBtn = (label, value) => ({
    padding: '10px 24px',
    background: tab === value ? 'var(--primary-blue)' : 'transparent',
    color: tab === value ? '#060505' : 'var(--primary-blue)',
    border: '2px solid var(--primary-blue)',
    borderRadius: '8px',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '0.95rem',
  });

  const badgeStyle = (status) => ({
    display: 'inline-block',
    padding: '3px 10px',
    borderRadius: '20px',
    fontSize: '0.8rem',
    fontWeight: 'bold',
    background: status === 'active' || status === 'published'
      ? 'rgba(71,85,34,0.15)'
      : 'rgba(180,60,60,0.12)',
    color: status === 'active' || status === 'published' ? '#0e4a43' : '#679bb2',
    border: `1px solid ${status === 'active' || status === 'published' ? '#065da4' : '#b43c3c'}`,
  });

  const thStyle = {
    padding: '12px',
    textAlign: 'left',
    background: '#042c2d',
    color: '#031313',
    fontWeight: 'bold',
    border: '1px solid #011c21',
  };

  const tdStyle = {
    padding: '12px',
    border: '1px solid #0f8573',
    verticalAlign: 'middle',
  };

  if (loading) return <div className="content"><p>Loading admin data...</p></div>;

  return (
    <div className="content">
      <h2>🛡️ Admin Dashboard</h2>

      <div style={{ display: 'flex', gap: '12px', marginBottom: '24px' }}>
        <button style={tabBtn(`Members (${users.length})`, 'users')} onClick={() => setTab('users')}>
          👥 Members ({users.length})
        </button>
        <button style={tabBtn(`All Posts (${posts.length})`, 'posts')} onClick={() => setTab('posts')}>
          📝 All Posts ({posts.length})
        </button>
      </div>

      {/* ── Members Tab ── */}
      {tab === 'users' && (
        <>
          <h3>Member Accounts</h3>
          {users.length === 0 ? (
            <p style={{ color: '#15343c',color: 'var(--text-main)', fontStyle: 'italic' }}>No members registered yet.</p>
          ) : (
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr>
                    <th style={thStyle}>Name</th>
                    <th style={thStyle}>Email</th>
                    <th style={thStyle}>Status</th>
                    <th style={thStyle}>Joined</th>
                    <th style={thStyle}>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(u => (
                    <tr key={u._id}>
                      <td style={tdStyle}>{u.name}</td>
                      <td style={tdStyle}>{u.email}</td>
                      <td style={tdStyle}>
                        <span style={badgeStyle(u.status)}>{u.status}</span>
                      </td>
                      <td style={tdStyle}>
                        {new Date(u.createdAt).toLocaleDateString()}
                      </td>
                      <td style={tdStyle}>
                        <button
                          onClick={() => toggleStatus(u._id)}
                          style={{
                            padding: '6px 14px',
                            border: 'none',
                            borderRadius: '6px',
                            fontWeight: 'bold',
                            cursor: 'pointer',
                            background: u.status === 'active' ? '#b43c3c' : '#475522',
                            color: '#fff',
                            fontSize: '0.85rem',
                          }}
                        >
                          {u.status === 'active' ? 'Deactivate' : 'Activate'}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* ── Posts Tab ── */}
      {tab === 'posts' && (
        <>
          <h3>All Posts</h3>
          {posts.length === 0 ? (
            <p style={{ color: '#8C7E72', fontStyle: 'italic' }}>No posts yet.</p>
          ) : (
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr>
                    <th style={thStyle}>Title</th>
                    <th style={thStyle}>Author</th>
                    <th style={thStyle}>Status</th>
                    <th style={thStyle}>Date</th>
                    <th style={thStyle}>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {posts.map(p => (
                    <tr key={p._id}>
                      <td style={tdStyle}>{p.title}</td>
                      <td style={tdStyle}>{p.author?.name}</td>
                      <td style={tdStyle}>
                        <span style={badgeStyle(p.status)}>{p.status}</span>
                      </td>
                      <td style={tdStyle}>
                        {new Date(p.createdAt).toLocaleDateString()}
                      </td>
                      <td style={tdStyle}>
                        {p.status === 'published' ? (
                          <button
                            onClick={() => removePost(p._id)}
                            style={{
                              padding: '6px 14px',
                              border: 'none',
                              borderRadius: '6px',
                              fontWeight: 'bold',
                              cursor: 'pointer',
                              background: '#b43c3c',
                              color: '#fff',
                              fontSize: '0.85rem',
                            }}
                          >
                            Remove
                          </button>
                        ) : (
                          <span style={{ color: '#8C7E72', fontSize: '0.85rem' }}>—</span>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default AdminPage;
